import{_ as s,o as t,c as o,ae as i,j as e,a}from"./chunks/framework.B6gjLfeO.js";const m=JSON.parse('{"title":"Advanced Journeys UI (HTML & CSS)","description":"","frontmatter":{"title":"Advanced Journeys UI (HTML & CSS)","slug":"advanced-journeys-ui-html-css"},"headers":[],"relativePath":"developer-hub/advanced-journeys-ui-html-css.md","filePath":"developer-hub/advanced-journeys-ui-html-css.md"}'),l={name:"developer-hub/advanced-journeys-ui-html-css.md"};function r(p,n,d,c,h,u){return t(),o("div",null,[...n[0]||(n[0]=[i(`<h2 id="css-editor" tabindex="-1">CSS Editor <a class="header-anchor" href="#css-editor" aria-label="Permalink to &quot;CSS Editor&quot;">​</a></h2><p>The Journeys CSS Editor is used to customize the look and feel of how HTML elements are to be displayed on screen.</p><h3 id="use-custom-font" tabindex="-1">Use Custom Font <a class="header-anchor" href="#use-custom-font" aria-label="Permalink to &quot;Use Custom Font&quot;">​</a></h3><p>Use the following code when <a href="./create-journey-banner-or-interstitial.html#2-configure-creatives">configuring creatives</a> <strong>CSS Editor</strong> to use a custom font:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@import url(&#39;https://fonts.googleapis.com/css?family=Source+Sans+Pro:600,900&#39;);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>#branch-banner {</span></span>
<span class="line"><span>  …</span></span>
<span class="line"><span>  font-family: &#39;Source Sans Pro&#39;, sans-serif;</span></span>
<span class="line"><span>  …</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="add-background-images" tabindex="-1">Add Background Images <a class="header-anchor" href="#add-background-images" aria-label="Permalink to &quot;Add Background Images&quot;">​</a></h3><p>Use the following code when <a href="./create-journey-banner-or-interstitial.html#2-configure-creatives">configuring creatives</a> <strong>CSS Editor</strong> to use a different background image to existing template objects:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>#branch-banner .branch-banner-content {</span></span>
<span class="line"><span>  …</span></span>
<span class="line"><span>background-image: url(&#39;url of your desired image&#39;);</span></span>
<span class="line"><span>  …</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="animating-journeys" tabindex="-1">Animating Journeys <a class="header-anchor" href="#animating-journeys" aria-label="Permalink to &quot;Animating Journeys&quot;">​</a></h3><p>Use the following code when <a href="./create-journey-banner-or-interstitial.html#2-configure-creatives">configuring creatives</a> <strong>CSS Editor</strong> to create an animation using <code>@keyframes</code> rule:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@keyframes example {</span></span>
<span class="line"><span>  0% {</span></span>
<span class="line"><span>    content: &quot;\\a\\a £5 OFF!&quot;;</span></span>
<span class="line"><span>    transform: translateX(-85%);</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span> …</span></span>
<span class="line"><span>100% {</span></span>
<span class="line"><span>    content: &quot;\\a\\a £5 OFF!&quot;;</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>.branch-banner-title::after {</span></span>
<span class="line"><span>  content: &quot;\\a\\a £5 OFF!&quot;;</span></span>
<span class="line"><span>  …</span></span>
<span class="line"><span>  animation-name: example;</span></span>
<span class="line"><span>  animation-duration: 3s;</span></span>
<span class="line"><span>  animation-iteration-count: infinite;</span></span>
<span class="line"><span>}</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">Caveats</p><p>It is possible to use GIFs, but compared to CSS animations, GIFs are:</p><ul><li>Larger</li><li>Take longer to load</li><li>Inflexible (have to create a new GIF anytime you want to change something)</li></ul></div><h3 id="remove-focus-indicator" tabindex="-1">Remove Focus Indicator <a class="header-anchor" href="#remove-focus-indicator" aria-label="Permalink to &quot;Remove Focus Indicator&quot;">​</a></h3><p>To remove unwanted focus indicator borders on your banners, navigate to the <strong>CSS Editor</strong> and add the following code when <a href="./create-journey-banner-or-interstitial.html#2-configure-creatives">configuring creatives</a>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>#branch-banner .branch-banner-content.focus: {</span></span>
<span class="line"><span>	outline: color of banner;</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="specific-screen-sizes-css" tabindex="-1">Specific Screen Sizes (CSS) <a class="header-anchor" href="#specific-screen-sizes-css" aria-label="Permalink to &quot;Specific Screen Sizes (CSS)&quot;">​</a></h3><p>There is an ability to customize banners for specific screen sizes or even potentially, specific devices, through the use of CSS @media queries. This is a feature of modern browsers and allows you to add logic and apply CSS formats based on the parameters provided by the browser.</p><ol><li><p>You can choose to do this at the <code>#branch-banner-iframe container</code> level or at the individual <code>#branch-banner objects</code> level.</p></li><li><p>Determine what property changes you want to make and tie them to what is available via <code>@media</code> query parameters. For example:</p><ul><li>You want to make the title, stars, reviews, and icons smaller for smaller screen devices.</li><li>You might want to provide special formatting for a very specific family of devices.</li></ul></li><li><p>Translate your logic into CSS code. Use resources on the web if you are unfamiliar with the syntax:</p><ul><li><a href="https://developer.mozilla.org/en-US/docs/Web/CSS/@media" target="_blank" rel="noreferrer">https://developer.mozilla.org/en-US/docs/Web/CSS/@media</a></li><li>Web search &quot;@media standard queries&quot; to find some work published to target specific device models, if desired</li><li>Here&#39;s an example that says, for browsers that report a screen width of 1px to 350px, set this CSS:</li></ul></li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@media only screen and (min-device-width: 200px) and (max-device-width: 350px) {</span></span>
<span class="line"><span>  #branch-banner .branch-banner-title {</span></span>
<span class="line"><span>    font-weight: bold;</span></span>
<span class="line"><span>    color: #333333;</span></span>
<span class="line"><span>    padding-bottom: 1px;</span></span>
<span class="line"><span>    font-size: 10px;</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>  #branch-banner .branch-banner-stars {</span></span>
<span class="line"><span>    display: inline-block;</span></span>
<span class="line"><span>    color: rgba(255, 180, 0, 1);</span></span>
<span class="line"><span>    letter-spacing: -2px;</span></span>
<span class="line"><span>    font-size: 14px;</span></span>
<span class="line"><span>    margin-left: -2px;</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>  #branch-banner .branch-banner-reviews {</span></span>
<span class="line"><span>    font-size: 10px;</span></span>
<span class="line"><span>    color: #777;</span></span>
<span class="line"><span>    display: inline-block;</span></span>
<span class="line"><span>    margin-left: 4px;</span></span>
<span class="line"><span>    position: relative;</span></span>
<span class="line"><span>    top: -1px;</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>  #branch-banner .branch-banner-icon img {</span></span>
<span class="line"><span>    width: 40px;</span></span>
<span class="line"><span>    height: 40px;</span></span>
<span class="line"><span>    border-radius: 10px;</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>  #branch-banner .branch-banner-icon {</span></span>
<span class="line"><span>    float: left;</span></span>
<span class="line"><span>    border-radius: 10px;</span></span>
<span class="line"><span>    width: 40px;</span></span>
<span class="line"><span>    height: 40px;</span></span>
<span class="line"><span>    margin-right: 10px;</span></span>
<span class="line"><span>    padding: 10px 0;</span></span>
<span class="line"><span>    position: relative;</span></span>
<span class="line"><span>    top: 50%;</span></span>
<span class="line"><span>    transform: translateY(-50%);</span></span>
<span class="line"><span>    -webkit-transform: translateY(-50%);</span></span>
<span class="line"><span>    -ms-transform: translateY(-50%);</span></span>
<span class="line"><span>    z-index: 2;</span></span>
<span class="line"><span>  }</span></span></code></pre></div><ol start="4"><li>Use the test feature to preview the changes in a separate browser instance while emulating different device models/sizes to ensure the banner renders as intended. Inspect the CSS of the page if necessary to validate that these properties are reflected in the real banner.</li><li>Lastly, make sure your logical operators do not have any loopholes or cases left without proper CSS formatting. One approach is an inverse block that reads: <code>@media not screen and (min-device-width: 1px) and (max-device-width: 350px) {</code> to catch all other screen sizes the only block above ignores.</li></ol><h2 id="html-editor" tabindex="-1">HTML Editor <a class="header-anchor" href="#html-editor" aria-label="Permalink to &quot;HTML Editor&quot;">​</a></h2><p>The Journeys HTML Editor is used to customize which elements are present in your banner/interstitial. You have access to all the <code>&lt;&gt;</code> elements that make up your Journeys creative for you to play around with.</p><h3 id="allowed-elements-attributes" tabindex="-1">Allowed Elements &amp; Attributes <a class="header-anchor" href="#allowed-elements-attributes" aria-label="Permalink to &quot;Allowed Elements &amp; Attributes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Element</th><th>Attributes</th></tr></thead><tbody><tr><td><code>&lt;&gt;</code></td><td>n/a</td></tr><tr><td><code>&lt;&gt;</code></td><td>n/a</td></tr><tr><td><code>&lt;&gt;</code></td><td>-<code>type</code> - <code>id</code></td></tr><tr><td><code>&lt;&gt;</code></td><td>n/a</td></tr><tr><td><code>&lt;&gt;</code></td><td>- <code>data-id</code> - <code>data-default</code> - <code>id</code> - <code>class</code> - <code>aria-label</code> - <code>data-star-count</code> - <code>alt</code> - <code>role</code> - <code>tabindex</code> - <code>title</code></td></tr><tr><td><code>&lt;&gt;</code></td><td>- <code>data-id</code> - <code>data-default</code> - <code>id</code> - <code>class</code> - <code>aria-label</code> - <code>src</code> - <code>alt</code> - <code>role</code> - <code>tabindex</code> - <code>title</code></td></tr><tr><td><code>&lt;&gt;</code></td><td>- <code>data-id</code> - <code>data-default</code> - <code>id</code> - <code>class</code> - <code>aria-label</code> - <code>style</code> - <code>alt</code> - <code>role</code> - <code>tabindex</code> - <code>title</code></td></tr><tr><td><code>&lt;&gt;</code></td><td>- <code>data-id</code> - <code>class</code></td></tr><tr><td><code>&lt;&gt;</code></td><td>- <code>data-id</code> - <code>id</code> - <code>class</code> - <code>aria-label</code> - <code>role</code> - <code>tabindex</code></td></tr><tr><td><code>&lt;&gt;</code></td><td>- <code>name</code> - <code>content</code></td></tr><tr><td><code>&lt;&gt;</code></td><td>- <code>data-id</code> - <code>data-default</code> - <code>id</code> - <code>class</code> - <code>aria-label</code> - <code>data-star-count</code> - <code>alt</code> - <code>role</code> - <code>tabindex</code> - <code>title</code></td></tr></tbody></table><h2 id="page-placement" tabindex="-1">Page Placement <a class="header-anchor" href="#page-placement" aria-label="Permalink to &quot;Page Placement&quot;">​</a></h2><h3 id="reduce-cumulative-layout-shift" tabindex="-1">Reduce Cumulative Layout Shift <a class="header-anchor" href="#reduce-cumulative-layout-shift" aria-label="Permalink to &quot;Reduce Cumulative Layout Shift&quot;">​</a></h3><p>Cumulative Layout Shift (CLS) is part of <a href="https://developers.google.com/speed/pagespeed/insights/" target="_blank" rel="noreferrer">Google&#39;s PageSpeed Insights</a> that measures the largest burst of layout shift scores for every unexpected layout shift that occurs during the entire lifespan of a page. The CLS score will vary based on the web page setup, the type of banner/interstitial, and page placement.</p><p>Google recommends reserving space for banners along with a placeholder option when the actual banner is not shown. Alternatively, this can be managed by using the CSS transform property in the Journeys editor.</p><p>Below are guidelines for reducing any negative contribution related to Journeys:</p><ol><li><p>Set the Page Placement of the banner/interstitial to the &quot;Customize Container (iFrame)&quot; option</p></li><li><p>Change the CSS based on the type of banner/interstitial:</p></li></ol>`,30),e("table",{tabindex:"0"},[e("thead",null,[e("tr",null,[e("th",null,"Page Placement Setting"),e("th",null,"Banner Type"),e("th",null,"Changes Needed"),e("th",null,"Example")])]),e("tbody",null,[e("tr",null,[e("td",null,"Inline"),e("td",null,"- Full Page Interstitial - Partial Interstitial - Top Banner"),e("td",null,[a("- Add "),e("code",null,'body { transform: translate(0, );="">'),a(" - Change value of top for "),e("code",null,'#branch-banner-iframe { top: -;="">'),a(" Please note the value of top is negative.")]),e("td",{"transform:":"","translate(0,":"","456px);":""},[a("# branch-banner-iframe { "),e("code",null,"top: -456px; left: 0; right: 0; border: 0; height: 100vh; z-index: 99999; box-shadow: 0 0 5px rgba(0, 0, 0, .35); width: 1px; min-width: 100%; position: absolute;"),a(" } body")])]),e("tr",null,[e("td",null,"Sticky"),e("td",null,"-Full Page Interstitial - Partial Interstitial - Top Banner"),e("td",null,[a("- Add "),e("code",null,'body > * { transform: translate(0, );="">'),a(" - Change value of top for "),e("code",null,'#branch-banner-iframe { top: -;="">'),a(" Please note the value of top is negative.")]),e("td",{"transform:":"","translate(0,":"","76px);":""},[a("# branch-banner-iframe { "),e("code",null,"top: -76px; left: 0; right: 0; border: 0; height: 100vh; z-index: 99999; box-shadow: 0 0 5px rgba(0, 0, 0, .35); width: 1px; min-width: 100%; position: absolute;"),a(" } body>*")])])])],-1)])])}const g=s(l,[["render",r]]);export{m as __pageData,g as default};
